		ref: init.ref,
		owner: init.owner,
		name: init.name,
		stars: init.stars,
		primaryLanguage: init.primaryLanguage,
	};
	jobs.set(id, job);
	return job;
}

export function getJob(id: string): Job | undefined {
	return jobs.get(id);
}

